import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set Fields',
    parameters: {
      assignments: {
        assignments: [
          {
            id: 'sample-field',
            name: 'message',
            value: 'Hello from n8n!',
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('basic-manual-set', 'Basic Manual Trigger + Set Node')
  .add(manualTrigger)
  .to(setNode);
